parameters.jsCode:
const item = $input.first();

// Safe access
const binary = item.binary?.data;

if (!binary) {
  throw new Error("No binary data found. Make sure Dropbox Download node is correct.");
}

// Safer filename extraction
const fileName =
  binary.fileName ||
  item.json["File Name"] ||
  item.json.name ||
  "unknown.md";

const mimeType = binary.mimeType;

// Get file buffer
const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');

// Convert to text
const fileContent = binaryBuffer.toString('utf-8');

return [
  {
    json: {
      fileName,
      mimeType,
      fileContent,
      timestamp: new Date().toISOString()
    }
  }
];

// get all incoming items from Merge node
const items = $input.all();

// find the item that contains AI extracted clauses
const aiItem = items.find(i => i.json.output);

// vendor clauses live inside output
const extracted = aiItem.json.output;

// remaining items = Notion Standard Clause records
const standards = items
  .filter(i => !i.json.output && i.json.property_clause_type)
  .map(i => i.json);

// helper to get standard clause by type
function getStandard(type){
  return standards.find(s => s.property_clause_type === type);
}


// clause types must match Notion select values
const clauseTypes = [
  "Payment Terms",
  "Penalties",
  "SLA",
  "Termination",
  "Renewal",
  "Liability",
  "Data Protection"
];

let deviations = [];
let comparison = {};

clauseTypes.forEach(type => {

  const std = getStandard(type);

  // convert to JSON key format used by AI output
  const key = type.toLowerCase().replace(" ", "_");

  const extractedText = extracted[key];
  const standardText = std?.property_standard_text || "";

  comparison[key] = {
  clause_type: type,
  extracted: extractedText,
  standard: standardText,
  risk_level_if_deviates: std?.property_risk_level_if_deviates || "Unknown"
};


});

return [{
  json: {
    clauses: extracted,
    comparison,
  }
}];

// nodes
const compare = $items("Compare Vendor vs Standard Clauses")[0].json.comparison;
const aiRisk = $items("AI Risk Analysis & Executive Report")[0].json.output.clause_risk_review;

// normalize helper (VERY IMPORTANT)
function normalize(text){
  return text
    .toLowerCase()
    .replace(/[\u00A0\u202F]/g, " ") // weird spaces → normal space
    .replace(/[^\w\s]/g, "")        // remove punctuation
    .replace(/\s+/g, " ")           // collapse spaces
    .trim();
}

// helper → get risk by clause name
function getRiskLevel(clauseType){
  const normalizedType = normalize(clauseType);

  const found = aiRisk.find(r =>
    normalize(r.clause_name) === normalizedType
  );

  return found ? found.risk_level : "Unknown";
}

const output = [];

for (const key of Object.keys(compare)) {

  const clause = compare[key];

  output.push({
    clause_type: clause.clause_type,
    vendor_clause: clause.extracted,
    standard_clause: clause.standard,
    risk_level: getRiskLevel(clause.clause_type)   
  });

}

return output.map(i => ({ json: i }));

