{
  "type": "object",
  "properties": {
    "clause_type": {
      "type": "string",
      "description": "Name of the clause being rewritten"
    },
    "revised_clause": {
      "type": "string",
      "description": "Improved clause wording aligned with company policy"
    }
  },
  "required": [
    "clause_type",
    "revised_clause"
  ]
}

parameters.jsCode:
const items = $input.all();

const combined = {};

for (const item of items) {
  const out = item.json.output || {};
  const type = out.clause_type;
  const text = out.revised_clause;

  if (!type || !text) continue;

  const key = type.toLowerCase().replace(/\s+/g, "_");
  combined[key] = text;
}

return [
  {
    json: {
      revised_clauses: combined
    }
  }
];

